class Solution:
    def minMutation(self, startGene: str, endGene: str, bank: List[str]) -> int:
        bank_set = set(bank)
        if endGene not in bank_set and startGene != endGene:
            return -1

        queue = deque()
        queue.append((startGene,0))
        visited = set()

        while queue:
            thisGene, depth = queue.pop()
            if thisGene == endGene:
                return depth
            string = list(thisGene)

            for i in range(len(string)):
                char = string[i]
                for ch in ['A','C','G','T']:
                    string[i] = ch
                    new_gene = ''.join(string)
                    if new_gene not in visited and new_gene in bank:
                        queue.append((new_gene, depth + 1))
                        visited.add(new_gene)

                string[i] = char

        return -1

class Solution:
    def minMutation(self, startGene: str, endGene: str, bank: List[str]) -> int:
        bank_set = set(bank)
        if endGene not in bank_set and startGene != endGene:
            return -1

        queue = deque()
        queue.append((startGene,0))
        visited = set()

        while queue:
            thisGene, depth = queue.popleft()
            if thisGene == endGene:
                return depth
            thisGene = list(thisGene)

            for i in range(len(thisGene)):
                char = thisGene[i]
                for ch in ['A','C','G','T']:
                    thisGene[i] = ch
                    new_gene = ''.join(thisGene)
                    if new_gene not in visited and new_gene in bank:
                        queue.append((new_gene, depth + 1))
                        visited.add(new_gene)

                thisGene[i] = char

        return -1
